SELECT application_id, loan_amount, loan_amount_term 
FROM loan_applications 
WHERE loan_status = 'Y' AND loan_amount > (
    SELECT AVG(loan_amount) 
    FROM loan_applications
);

SELECT AVG(loan_amount) AS average_loan_amount, MIN(loan_amount) AS minimum_loan_amount, MAX(loan_amount) AS maximum_loan_amount
FROM loan_applications
WHERE loan_type_id = (SELECT loan_type_id FROM loan_types WHERE loan_type_name = 'Personal Loan');

SELECT AVG(customers.credit_score) AS average_credit_score
FROM customers
JOIN loan_applications ON customers.customer_id = loan_applications.customer_id
WHERE loan_applications.loan_type_id != (
    SELECT loan_type_id FROM loan_types WHERE loan_type_name = 'Personal Loan'
);

SELECT la.application_id, la.loan_amount, la.loan_amount_term, la.application_status, lt.loan_type_name, lt.description
FROM loan_applications la
INNER JOIN loan_types lt ON la.loan_type_id = lt.loan_type_id;

SELECT c.customer_id, c.email
FROM customers c
WHERE c.customer_id IN (
    SELECT la.customer_id
    FROM loan_applications la
    WHERE la.loan_amount > (
        SELECT AVG(loan_amount) AS avg_loan_amount
        FROM loan_applications
    )
);

SELECT lt.loan_type_name, lt.description
FROM loan_types lt
WHERE lt.min_loan_amount < (
    SELECT AVG(la.loan_amount) FROM loan_applications la
);

SELECT AVG(customers.annual_income) AS average_income
FROM customers
JOIN loan_applications ON customers.customer_id = loan_applications.customer_id;

SELECT officer_name, (STRFTIME('%Y', 'now') - STRFTIME('%Y', hire_date)) as inactive_years
FROM loan_officers
WHERE active_status = 'inactive';

SELECT gender, AVG(annual_income) AS average_income 
FROM (
    SELECT gender, annual_income 
    FROM customers 
    WHERE employment_status = 'Employed'
    AND annual_income > (
        SELECT AVG(annual_income) FROM customers
    )
) 
GROUP BY gender;
